  ('social-worker-moex-00061', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一名無親友支持系統的失業單親父親，其居住社區的托育服務資源稀缺且昂貴，每次應徵工作時 就將5歲的孩子獨自留在家中而觸法。從系統理論觀點來看，案例中的家庭系統處遇目標，不包 括下列何者？', '["藉由社區系統的改變，帶動家庭系統功能的提升", "在維持現況的過程中，協助家庭系統維持穩定", "藉由打破親子次系統的界線，引發家庭去改變不良的互動模式", "為確保家庭系統維持生存，使其能從外在環境獲得所需的訊息與資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
