  ('social-worker-moex-00063', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '增強權能（empowerment）是一種歷程，目的在協助服務對象取得決定權與行動權。對於此歷程 的介入策略之敘述，下列何者錯誤？', '["發展個人與人連結的能力來抵抗制度性壓迫", "鼓勵服務對象透過社會互動促進更多的個人與人際權能", "增進服務對象因應與改變環境的技巧", "協助服務對象爭取生活資源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00064', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '女性貧窮是社會工作服務中面臨的重要議題，下列何種工作方法不是基變社會工作者的觀點？', '["參加女性勞動協會發起遊行倡導修法", "關注蒐集女性在弱勢家庭戶長的比例", "針對女性服務對象進行心理輔導", "提升第一線公務人員對女性貧窮議題的認識"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
